def solve(arr):
    n = len(arr)
    mn, mx = min(arr), max(arr)
    if (mx - mn) % (n - 1) != 0:
        return False
    diff = (mx - mn) // (n - 1)
    s = set(arr)
    if diff == 0:
        return len(s) == 1
    if len(s) != n:
        return False
    return all((mn + i * diff) in s for i in range(n))


class Solution:
    def canMakeArithmeticProgression(self, arr):
        return solve(arr)

