var canMakeArithmeticProgression = function(arr) {
    const a = [...arr].sort((x, y) => x - y);
    const diff = a[1] - a[0];
    for (let i = 2; i < a.length; i++) {
        if (a[i] - a[i - 1] !== diff) return false;
    }
    return true;
};
